#include<bits/stdc++.h>
using namespace std;
const long long mod=998244353;
long long l[200010],r[200010],b[200010];
long long s1[200010],s2[200010];
int main()
{
    long long n,m,Q;
    scanf("%lld%lld%lld",&n,&m,&Q);
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld%lld%lld",&l[i],&r[i],&b[i]);
        b[i]%=mod;
        s1[i]=(s1[i-1]+(r[i]-l[i]+1)%mod*b[i]%mod)%mod;
        s2[i]=(s2[i-1]+(r[i]-l[i]+1)%mod*(b[i]*b[i]%mod)%mod)%mod;
    }
    while(Q--)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        long long p=lower_bound(l+1,l+1+m,x)-l,q=upper_bound(r+1,r+1+m,y)-r-1;
        long long sum1=((s1[q]-s1[p-1])%mod+mod)%mod,sum2=((s2[q]-s2[p-1])%mod+mod)%mod;
        if(p!=1&&x<=r[p-1])
        {
            sum1=(sum1+b[p-1]*((r[p-1]-x+1)%mod)%mod)%mod;
            sum2=(sum2+b[p-1]*b[p-1]%mod*((r[p-1]-x+1)%mod)%mod)%mod;
        }
        if(q!=m&&l[q+1]<=y)
        {
            sum1=(sum1+b[q+1]*((y-l[q+1]+1)%mod)%mod)%mod;
            sum2=(sum2+b[q+1]*b[q+1]%mod*((y-l[q+1]+1)%mod)%mod)%mod;
        }
        // printf("sum1=%lld sum2=%lld\n",sum1,sum2);
        printf("%lld\n",(((y-x+1)%mod*sum2%mod-sum1*sum1%mod)%mod+mod)%mod);
    }
    return 0;
}
